function setConditionalBackgroundColors() {
  var sheet = SpreadsheetApp.getActiveSheet();
  var dataRange = sheet.getDataRange();
  var numRows = dataRange.getNumRows();
  var values = dataRange.getValues();

  var conditionalBgColors = new Array(numRows);
  var isChangeRequired;

  for (var i = 0; i < numRows; i++) {
    isChangeRequired = true;
    conditionalBgColors[i] = new Array(dataRange.getNumColumns());
    var firstColValue = values[i][0];

    if (firstColValue.match(/(day|ime|of)$/)) {
      isChangeRequired = false;
    }

    for (var j = 0; j < dataRange.getNumColumns(); j++) {
      if (isChangeRequired) {
        if (j === 2 || j === 7 || j === 12 || j === 17) {
          conditionalBgColors[i][j] = "#DFE3E7";
        } else if (j === 3 || j === 8 || j === 13 || j === 18) {
          conditionalBgColors[i][j] = "#D3D3DF";
        }
      }
    }
  }

  dataRange.setBackgrounds(conditionalBgColors);
}
```

